from __future__ import annotations

import os
from dataclasses import dataclass

from PyQt6.QtCore import QLocale


SUPPORTED_LANGUAGES = {"ja", "en"}


def normalize_language(language: str | None) -> str:
    if not language:
        return "ja"
    primary = language.replace("-", "_").split("_", 1)[0].lower()
    if primary in SUPPORTED_LANGUAGES:
        return primary
    return "en"


def detect_system_language() -> str:
    for key in ("LC_ALL", "LC_MESSAGES", "LANGUAGE", "LANG"):
        value = os.environ.get(key)
        if value:
            return normalize_language(value)
    return normalize_language(QLocale.system().name())


@dataclass(frozen=True)
class Translator:
    language: str
    messages: dict[str, str]

    def __call__(self, key: str, **kwargs: object) -> str:
        template = self.messages.get(key)
        if template is None:
            raise KeyError(f"missing translation key: {key}")
        return template.format(**kwargs)


def build_translator(language: str | None = None) -> Translator:
    normalized = normalize_language(language)
    return Translator(language=normalized, messages=TRANSLATIONS[normalized])


